definition.script:
pipeline {
    agent any
    environment {
      NOMBRE = "world"
      DOCKERHUB_CREDENTIALS = credentials('kk')
    }    
    parameters {
      choice choices: ['Hola', 'Adios'], name: 'FORMULA'
    }
    stages {
        stage('Hello') {
            steps {
                echo "'${params.FORMULA} ${NOMBRE}', ${env.JOB_NAME} ${currentBuild.currentResult}"
            }
        }
        stage('Deliver') {
            steps {
                input cancel: 'Abortar', message: 'Ha superado el umbral de calidad, ¿continuo con el despliegue?', ok: 'Desplegar'
            }
        }

        // stage('Secreto') {
        //     steps {
        //         echo "'Hello ${DOCKERHUB_CREDENTIALS_USR}', contraseña: ${DOCKERHUB_CREDENTIALS_PSW}"
        //     }
        // }
    }
}
